<?php
declare(strict_types=1);
namespace App\Core\BrowserAnalytics;
use PDO;
final readonly class EcosistemaBrowserAnalyticsEventRepository{public function __construct(private PDO $pdo){}
public function listRecentEvents(int $tenantId,int $limit=100): array{$safeLimit=max(1,min(500,$limit));$sql='SELECT id,session_id,pageview_id,campaign_id,landing_page_id,short_link_id,crm_lead_id,event_type,event_name,element_id,element_text,element_url,value_numeric,value_text,score_points,metadata_json,occurred_at FROM browser_analytics_events WHERE tenant_id=:tenant_id ORDER BY occurred_at DESC,id DESC LIMIT :limit';$stmt=$this->pdo->prepare($sql);$stmt->bindValue(':tenant_id',$tenantId,PDO::PARAM_INT);$stmt->bindValue(':limit',$safeLimit,PDO::PARAM_INT);$stmt->execute();return $stmt->fetchAll(PDO::FETCH_ASSOC)?:[];}
public function listEventsForPageview(int $tenantId,int $pageviewId,int $limit=100): array{$safeLimit=max(1,min(500,$limit));$sql='SELECT id,session_id,pageview_id,campaign_id,landing_page_id,short_link_id,crm_lead_id,event_type,event_name,element_id,element_text,element_url,value_numeric,value_text,score_points,metadata_json,occurred_at FROM browser_analytics_events WHERE tenant_id=:tenant_id AND pageview_id=:pageview_id ORDER BY occurred_at DESC,id DESC LIMIT :limit';$stmt=$this->pdo->prepare($sql);$stmt->bindValue(':tenant_id',$tenantId,PDO::PARAM_INT);$stmt->bindValue(':pageview_id',$pageviewId,PDO::PARAM_INT);$stmt->bindValue(':limit',$safeLimit,PDO::PARAM_INT);$stmt->execute();return $stmt->fetchAll(PDO::FETCH_ASSOC)?:[];}
public function summarizeEvents(int $tenantId): array{$sql='SELECT COUNT(*) AS total_events,COUNT(DISTINCT pageview_id) AS total_pageviews,COUNT(DISTINCT session_id) AS total_sessions,MAX(occurred_at) AS latest_occurred_at,COALESCE(AVG(score_points),0) AS avg_score_points FROM browser_analytics_events WHERE tenant_id=:tenant_id';$stmt=$this->pdo->prepare($sql);$stmt->bindValue(':tenant_id',$tenantId,PDO::PARAM_INT);$stmt->execute();return (array)($stmt->fetch(PDO::FETCH_ASSOC)?:[]);}}
